#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}

CI dx[4] = {0, 0, -1, 1},dy[4] = {1, -1, 0, 0},MAXN=1e3+5;
int a[MAXN][MAXN];
int c[MAXN][MAXN];
int n;
void bfs()
{
	queue<int>nx;
	queue<int>ny;
	queue<int>nt;
	int x, y, t;
	nx.push(1);
	ny.push(1);
	nt.push(0);
	while (nx.size())
	{
		x = nx.front();
		y = ny.front();
		t = nt.front();
		nx.pop();
		ny.pop();
		nt.pop();
		if (x == n && y == n && a[x][y] >= t)
		{
			puts("Yes");
			return;
		}
		for (int i = 0; i < 4; i++)
		{
			if (x + dx[i] > 0 && x + dx[i] <= n && y + dy[i] > 0 && y + dy[i] <= n)
			{
				if (!c[x + dx[i]][y + dy[i]])
				{
					if (a[x][y] >= t)
					{
						nx.push(x + dx[i]);
						ny.push(y + dy[i]);
						nt.push(t + 1);
						c[x + dx[i]][y + dy[i]] = true;
					}
				}
			}
		}
	}
	puts("No");
}
int main(void)
{
	int t;
	cin >> t;
	while (t--)
	{
		cin >> n;
		memset(a, 0x3f, sizeof a);
		memset(c, 0, sizeof c);
		for (int i = 1; i <= 2 * n - 2; ++i)
		{
			int x, y;
			cin >> x >> y;
			a[x][y] = i;
		}
		bfs();
	}
	return false;
}
